setMethod("close", "H5ParcellatedMultiScan", function(con, ...) {
  # All runs share the same H5File handle, so we only need to close it once
  if (length(con@runs) > 0 && !is.null(con@runs[[1]]@obj)) {
    safe_h5_close(con@runs[[1]]@obj)
  }
  invisible(NULL)
})

